Layer.OnCommand:
%function(self)
		self:x( SCREEN_LEFT+10 );
		self:y( SCREEN_CENTER_Y+(477-240) );
		self:horizalign('left');
		self:queuecommand('ProfileCheck');
		end

%function(self)
		self:x( SCREEN_RIGHT-10 );
		self:y( SCREEN_CENTER_Y+(477-240) );
		self:horizalign('right');
		self:queuecommand('ProfileCheck');
		end
